const statsRow     = $('Get Stats').first()?.json || {};
const recent       = $('Get Recent Complaints').all().map(i => i.json);
const productivity = $('Get Productivity').all().map(i => i.json);

return [{ json: {
  success: true,
  stats: {
    totalAll:     parseInt(statsRow.total_all    || 0),
    totalOpen:    parseInt(statsRow.total_open   || 0),
    totalClosed:  parseInt(statsRow.total_closed || 0),
    loggedToday:  parseInt(statsRow.logged_today || 0),
    loggedWeek:   parseInt(statsRow.logged_week  || 0),
    loggedMonth:  parseInt(statsRow.logged_month || 0),
    closedToday:  parseInt(statsRow.closed_today || 0),
    closedWeek:   parseInt(statsRow.closed_week  || 0),
    closedMonth:  parseInt(statsRow.closed_month || 0),
    critical:     parseInt(statsRow.critical     || 0)
  },
  recentComplaints: recent,
  productivity
} }];
